                if (newCost < dp[newI][newJ]) {
                    dp[newI][newJ] = newCost;
                    pq.push({newCost, {newI, newJ}});
                }
            }

            // If we can't move further, wait
            if (i + 1 >= rows && j + 1 >= cols) {
                break;
            }

            // Wait for 1 second (even time)
